class ReservationService {
  async createReservation(
    eventId: string,
    seatId: string,
    userId: string,
    idempotencyKey: string
  ) {
    return await db.transaction(async (tx) => {
      // 1. Check Idempotency
      const existing = await outboxRepo
        .findByIdempotencyKey(idempotencyKey, tx);
      if (existing) return existing;

      // 2. Reserve Seat
      await seatRepo.updateState(
        eventId, seatId, 'HELD', currentVersion, tx
      );

      // 3. Write Outbox
      const orderId = uuidv4();
      await outboxRepo.insert({
        type: 'SeatReserved',
        payload: { eventId, seatId, userId, orderId },
        idempotencyKey
      }, tx);

      // 4. Audit Log
      await auditRepo.log('ReserveSeat', { eventId, seatId, userId }, tx);

      return { reservationId, orderId };
    });
  }
}

class SeatAvailabilityService {
  async getAvailableSeats(eventId: string): Promise<Seat[]> {
    // 1. Try Cache
    const cached = await redis.get(`event:${eventId}:seats`);
    if (cached) return JSON.parse(cached);

    // 2. Cache Miss → DB
    const seats = await seatRepo.findByEvent(eventId);

    // 3. Populate Cache
    await redis.setex(
      `event:${eventId}:seats`,
      5,  // TTL 5s
      JSON.stringify(seats)
    );

    return seats;
  }
}
